module RefModule( A, B, Ci, S, Co );input A, B, Ci;
  output S, Co;

  wire obf_S1, C1, C2;

  // XOR gate to calculate the sum of A and B
  assign obf_S1 = A ^ B;

  // XOR gate to calculate the sum of obf_S1 and Ci
  assign S = obf_S1 ^ Ci;

  // AND gate to calculate the carry-out value
  assign C1 = A & B;
  assign C2 = obf_S1 & Ci;

  // OR gate to calculate the carry-out
  assign Co = C1 | C2;
endmodule
